# Problem: Implement a simplified pytest-style fixture system.
# Fixtures are registered by name, and test functions declare dependencies
# via their parameter names. The system resolves fixtures by inspecting
# the test function's signature and calling the matching fixture factories.
#
# Approach:
#   - Use a dictionary to map fixture names to their factory callables.
#   - Use func.__code__.co_varnames[:co_argcount] to extract parameter names.
#   - For each parameter, look up the fixture, call it, and collect results.
#   - run_test wraps execution in try/except to produce a TestResult.
#
# Time complexity: O(n) per resolve, where n = number of parameters.
# Space complexity: O(n) for the resolved values dict.
#
# Key steps:
#   1. TestResult stores name, passed, and error.
#   2. FixtureManager maintains a registry dict and provides register/resolve/run_test.
#   3. resolve() extracts param names via co_varnames/co_argcount, looks up each fixture.
#   4. run_test() calls resolve(), invokes the test, catches exceptions.
#   5. @fixture decorator registers into the module-level default_manager.


class TestResult:
    def __init__(self, name: str, passed: bool, error: str | None = None):
        self.name = name
        self.passed = passed
        self.error = error


class FixtureManager:
    def __init__(self):
        self._fixtures = {}  # maps fixture name -> callable

    def register(self, func):
        # Register using the function's __name__ as the key; overwrites duplicates
        self._fixtures[func.__name__] = func

    def resolve(self, func):
        # Extract only the parameter names (not all local vars)
        param_names = func.__code__.co_varnames[:func.__code__.co_argcount]
        resolved = {}
        for name in param_names:
            if name not in self._fixtures:
                raise ValueError(f"Fixture '{name}' not found")
            resolved[name] = self._fixtures[name]()  # call the fixture factory
        return resolved

    def run_test(self, func):
        try:
            resolved = self.resolve(func)
            func(**resolved)
            return TestResult(name=func.__name__, passed=True)
        except Exception as e:
            return TestResult(name=func.__name__, passed=False, error=str(e))


default_manager = FixtureManager()


def fixture(func):
    # Register the function as a fixture in the global manager, return it unchanged
    default_manager.register(func)
    return func
